export const contraindications = {"$comment":"Practice-based movement-screening heuristics (Grade D) mapping a reported injury region to movement_patterns the plan engine should avoid. exclude_patterns are avoided at any severity; caution_patterns are additionally avoided at moderate/severe. Not medical advice — see content/05-recovery/injury-management.","regions":{"lower-back":{"exclude_patterns":[],"caution_patterns":["hinge","squat"],"note":"Loaded spinal flexion/compression can aggravate low-back injury; prefer machine/supported leg and back work.","evidence_grade":"D"},"knee":{"exclude_patterns":[],"caution_patterns":["lunge","squat","isolation-knee-extension"],"note":"Loaded knee flexion (squats, lunges) and full-range knee extension are the classic patellofemoral/knee aggravators. At mild you keep everything (just train in a pain-free range and prefer machine/controlled ranges); at moderate/severe these are pulled and direct quad work is minimised in favour of hamstring, hip and calf work while the knee settles.","evidence_grade":"D"},"shoulder":{"exclude_patterns":["vertical-push"],"caution_patterns":["horizontal-push","isolation-shoulder-abduction"],"note":"Overhead pressing and the lateral-raise abduction arc are the classic irritated-shoulder aggravators (impingement / painful arc). Overhead pressing is avoided at any severity; at moderate/severe, hard horizontal pressing and lateral raises are pulled too — prefer neutral-grip machine work and pulls in a pain-free range.","evidence_grade":"D"},"elbow":{"exclude_patterns":[],"caution_patterns":["isolation-elbow-extension","isolation-elbow-flexion"],"note":"Direct arm isolation can aggravate elbow tendinopathy; reduce volume and prefer neutral grips.","evidence_grade":"D"},"wrist":{"exclude_patterns":["isolation-wrist"],"caution_patterns":[],"note":"Loaded wrist flexion/extension; avoid direct wrist work while symptomatic.","evidence_grade":"D"},"hip":{"exclude_patterns":[],"caution_patterns":["hinge","squat"],"note":"Deep loaded hip flexion; prefer controlled ranges and machine support.","evidence_grade":"D"},"neck":{"exclude_patterns":["isolation-neck"],"caution_patterns":[],"note":"Avoid direct neck loading while symptomatic.","evidence_grade":"D"},"ankle":{"exclude_patterns":[],"caution_patterns":["isolation-plantarflexion"],"note":"Loaded plantarflexion; reduce calf work while symptomatic.","evidence_grade":"D"}}};
